"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[58497],{28707(e,t,a){a.r(t),a.d(t,{assets:()=>l,contentTitle:()=>o,default:()=>d,frontMatter:()=>s,metadata:()=>r,toc:()=>c});const r=JSON.parse('{"id":"UserGuide/C07_Pattern_matching/S10_Pattern_matching_algorithm_for_advanced_users","title":"Pattern matching algorithm (for advanced users)","description":"Normalized grayscale correlation is widely used in industry for pattern matching applications. Although in many cases you do not need to know how the search operation is performed, an understanding of the algorithm can sometimes help you pick an optimal search strategy.","source":"@site/docs/UserGuide/C07_Pattern_matching/S10_Pattern_matching_algorithm_for_advanced_users.md","sourceDirName":"UserGuide/C07_Pattern_matching","slug":"/UserGuide/C07_Pattern_matching/S10_Pattern_matching_algorithm_for_advanced_users","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C07_Pattern_matching/S10_Pattern_matching_algorithm_for_advanced_users","draft":false,"unlisted":false,"tags":[],"version":"current","frontMatter":{"doctype":"UserGuide","part":"2D processing and analysis","chapter":"Pattern_matching","section":"Pattern_matching_algorithm_for_advanced_users","module_tag":"pat","product":"Aurora-Imaging-Library-user-guide","version":1100,"path":"UserGuide / 2D processing and analysis / pattern / Pattern matching algorithm for advanced users"},"sidebar":"userGuideSidebar","previous":{"title":"Speeding up the search","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C07_Pattern_matching/S09_Speeding_up_the_search"},"next":{"title":"Pattern matching examples","permalink":"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C07_Pattern_matching/S11_Pattern_matching_examples"}}');var n=a(74848),i=a(28453);const s={doctype:"UserGuide",part:"2D processing and analysis",chapter:"Pattern_matching",section:"Pattern_matching_algorithm_for_advanced_users",module_tag:"pat",product:"Aurora-Imaging-Library-user-guide",version:1100,path:"UserGuide / 2D processing and analysis / pattern / Pattern matching algorithm for advanced users"},o="Pattern matching algorithm (for advanced users)",l={},c=[{value:"Normalized correlation",id:"normalized-correlation",level:2},{value:"Hierarchical search",id:"hierarchical-search",level:2},{value:"Search region",id:"search-region",level:2},{value:"Search heuristics",id:"search-heuristics",level:2},{value:"Subpixel accuracy",id:"subpixel-accuracy",level:2}];function h(e){const t={a:"a",blockquote:"blockquote",code:"code",em:"em",h1:"h1",h2:"h2",header:"header",p:"p",strong:"strong",sup:"sup",...(0,i.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(t.header,{children:(0,n.jsx)(t.h1,{id:"pattern-matching-algorithm-for-advanced-users",children:"Pattern matching algorithm (for advanced users)"})}),"\n",(0,n.jsx)(t.p,{children:"Normalized grayscale correlation is widely used in industry for pattern matching applications. Although in many cases you do not need to know how the search operation is performed, an understanding of the algorithm can sometimes help you pick an optimal search strategy."}),"\n",(0,n.jsx)(t.h2,{id:"normalized-correlation",children:"Normalized correlation"}),"\n",(0,n.jsxs)(t.p,{children:["The correlation operation can be seen as a form of convolution, where the pattern matching model is analogous to the convolution kernel (see ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/UserGuide/C04_Advanced_image_processing/S02_Custom_spatial_filters",children:"Custom spatial filters"}),"). Ordinary (un-normalized) correlation is exactly the same as a convolution:"]}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"[Image: UnnormalcorrEq.png]"})}),"\n",(0,n.jsxs)(t.p,{children:["In other words, for each result, the ",(0,n.jsx)(t.em,{children:"N"})," pixels of the model are multiplied by the ",(0,n.jsx)(t.em,{children:"N"}),' underlying image pixels, and these products are summed. Note, the model does not have to be rectangular because it can contain "don\'t care" pixels that are completely ignored during the calculation. When the correlation function is evaluated at every pixel in the target image, the locations where the result is largest are those where the surrounding image is most similar to the model. The search algorithm then has to locate these peaks in the correlation result, and return their positions.']}),"\n",(0,n.jsxs)(t.p,{children:["Unfortunately, with ordinary correlation, the result increases if the image gets brighter. In fact, the function reaches a maximum when the image is uniformly white, even though at this point it no longer looks like the model. The solution is to use a more complex, normalized version of the correlation function (the subscripts have been removed for clarity, but the summation is still over the ",(0,n.jsx)(t.em,{children:"N"}),' model pixels that are not "don\'t cares"):']}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"[Image: NormalCorrEq.png]"})}),"\n",(0,n.jsx)(t.p,{children:"With this expression, the result is unaffected by linear changes (constant gain and offset) in the image or model pixel values. The result reaches its maximum value of 1 where the image and model match exactly, gives 0 where the model and image are uncorrelated, and is negative where the similarity is less than might be expected by chance."}),"\n",(0,n.jsxs)(t.p,{children:["In our case, we are not interested in negative values, so results are clipped to 0. In addition, we use _r",(0,n.jsx)(t.sup,{children:"2"})," _ instead of ",(0,n.jsx)(t.em,{children:"r"})," to avoid the slow square-root operation. Finally, the result is converted to a percentage, where 100% represents a perfect match. So, the match score returned by ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatGetResult",children:(0,n.jsx)(t.code,{children:"MpatGetResult"})})," is actually:"]}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.code,{children:"_Score_ = max(_r_, 0)<sup>2</sup> x 100%"})}),"\n",(0,n.jsx)(t.p,{children:"Note, some of the terms in the normalized correlation function depend only on the model, and hence can be evaluated once and for all when the model is defined. The only terms that need to be calculated during the search are:"}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"[Image: SearchTerms.png]"})}),"\n",(0,n.jsx)(t.p,{children:"This amounts to two multiplications and three additions for each model pixel."}),"\n",(0,n.jsxs)(t.p,{children:["The sums used to compute the correlation function can be retrieved using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatGetResult",children:(0,n.jsx)(t.code,{children:"MpatGetResult"})}),". The retrievable sums are the following:"]}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"[Image: pat_result_sums.png]"})}),"\n",(0,n.jsxs)(t.p,{children:["The number of pixels ",(0,n.jsx)(t.em,{children:"N"})," is also available using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatGetResult",children:(0,n.jsx)(t.code,{children:"MpatGetResult"})}),". The above sums are only available if they are saved in the result buffer using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_SAVE_SUMS"})})," set to ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_ENABLE"})}),". These sums can be used, for example, to assess the model or target intensity level and contrast."]}),"\n",(0,n.jsxs)(t.blockquote,{children:["\n",(0,n.jsxs)(t.p,{children:[(0,n.jsx)(t.strong,{children:"Note:"})," Note that the correlation function calculated with the retrieved sums, will probably differ from the score returned by ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatGetResult",children:(0,n.jsx)(t.code,{children:"MpatGetResult"})}),". Although the score is derived from the correlation function, it also depends on the first and last subsampling levels chosen, optimization schemes and subpixel interpolation."]}),"\n"]}),"\n",(0,n.jsxs)(t.p,{children:["On a typical computer, the multiplications alone account for most of the computation time. A typical application might need to find a 128x128-pixel model in a 512x512-pixel image. In such a case, the total number of multiplications needed for an exhaustive search is ",(0,n.jsx)(t.code,{children:"2x512<sup>2</sup>x128<sup>2</sup>"}),", or over 8 billion. On a typical computer, this would take a few minutes, much more than the 5 msec or so the search actually takes. Clearly, ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatFind",children:(0,n.jsx)(t.code,{children:"MpatFind"})})," does much more than simply evaluate the correlation function at every pixel in the search region and return the location of the peak scores."]}),"\n",(0,n.jsx)(t.h2,{id:"hierarchical-search",children:"Hierarchical search"}),"\n",(0,n.jsx)(t.p,{children:"A reliable method of reducing the number of computations is to perform a so-called hierarchical search. Basically, a series of smaller, lower-resolution versions of both the image and the model are produced, and the search begins on a much-reduced scale. This series of subsampled images is sometimes called a resolution pyramid, because of the shape formed when the different resolution levels are stacked on top of each other."}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"[Image: Hierarchy.png]"})}),"\n",(0,n.jsx)(t.p,{children:"Each level of the pyramid is half the size of the previous one, and is produced by applying a low-pass filter before subsampling. If the resolution of an image or model is 512x512 at level 0, then at level 1 it is 256x256, at level 2 it is 128x128, and so on. Therefore, the higher the level in the pyramid, the lower the resolution of the image and model."}),"\n",(0,n.jsx)(t.p,{children:"The search starts at low resolution to quickly find likely match candidates. It proceeds to higher and higher resolutions to refine the positional accuracy and make sure that the matches found at low resolution actually were occurrences of the model. Because the position is already known from the previous level (to within a pixel or so), the correlation function need be evaluated only at a very small number of locations."}),"\n",(0,n.jsx)(t.p,{children:"Since each higher level in the pyramid reduces the number of computations by a factor of 16, it is usually best to start at as high a level as possible. However, the search algorithm must trade off the reduction in search time against the increased chance of not finding the pattern at very low resolution. Therefore, it chooses a starting level according to the size of the model and the characteristics of the pattern. In the application described earlier (128x128 model and 512x512 image), it might start the search at level 4, which would mean using an 8x8 version of the model and a 32x32 version of the target image."}),"\n",(0,n.jsxs)(t.p,{children:["To determine the default first and last resolution levels, use ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatInquire",children:(0,n.jsx)(t.code,{children:"MpatInquire"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatInquire",children:(0,n.jsx)(t.code,{children:"M_PROC_FIRST_LEVEL"})})," and ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatInquire",children:(0,n.jsx)(t.code,{children:"M_PROC_LAST_LEVEL"})}),", respectively. If required, you can change the first and last resolution levels, using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_FIRST_LEVEL"})})," and ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_LAST_LEVEL"})})," to either a specific or the maximum possible level, repetitively. You can set the first resolution level to a specific value or you can have Aurora Imaging Library automatically set the best first level, based on the model's size or its content."]}),"\n",(0,n.jsxs)(t.p,{children:["When dealing with images without much fine detail, you should have Aurora Imaging Library automatically select the first resolution level from the model's size (using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_AUTO_SIZE_BASED"})}),"). This can provide a faster search, but fine details can be lost when dealing with larger images. In cases where fine details are present in larger target images, you should have Aurora Imaging Library automatically select a first resolution level from the model's content (using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_AUTO_CONTENT_BASED"})}),"). This intelligent analysis is typically slower, but can provide more robust results."]}),"\n",(0,n.jsxs)(t.p,{children:["The logic of a hierarchical search accounts for a seemingly counter-intuitive characteristic of ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatFind",children:(0,n.jsx)(t.code,{children:"MpatFind"})}),": large models tend to be found faster than small ones. This is because a small model cannot be subsampled to a large extent without losing all detail. Therefore, the search must begin at fairly high resolution (low level), where the relatively large search region results in a longer search time. Thus, small models can only be found quickly in fairly small search regions."]}),"\n",(0,n.jsxs)(t.p,{children:["Note that the pyramidal representation of the buffer is generated each time ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatFind",children:(0,n.jsx)(t.code,{children:"MpatFind"})})," is called. However, you can save the pyramidal representation of the buffer (generated when ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatFind",children:(0,n.jsx)(t.code,{children:"MpatFind"})})," is called) in the result buffer, using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_TARGET_CACHING"})}),". This pyramidal representation is re-used by consecutive calls to ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatFind",children:(0,n.jsx)(t.code,{children:"MpatFind"})})," as long as the same result buffer is used and the image, search region, and model size are not modified."]}),"\n",(0,n.jsx)(t.h2,{id:"search-region",children:"Search region"}),"\n",(0,n.jsx)(t.p,{children:"A zero-overscan technique is used to search for partially occluded occurrences near the border of the target image. However, this can lead to lower score and lower accuracy. In the example below, the left-most occurrence, which overlaps the border of the target image, would yield a lower score than the right-most occurrence."}),"\n",(0,n.jsx)(t.p,{children:(0,n.jsx)(t.em,{children:"[Image: pattern_matching_region.png]"})}),"\n",(0,n.jsx)(t.h2,{id:"search-heuristics",children:"Search heuristics"}),"\n",(0,n.jsxs)(t.p,{children:["Even though performed at very low resolution, the initial search still accounts for most of the computation time if the correlation is performed at every pixel in the search region. On most models, match peaks (pixel locations where the surrounding image is most similar to the model, and correlation results are largest) are several pixels wide. These can be found without evaluating the correlation function everywhere. ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatPreprocess",children:(0,n.jsx)(t.code,{children:"MpatPreprocess"})})," analyzes the shape of the match peak produced by the model, and determines if it is safe to try to find peaks faster. If the pattern produces a very narrow match peak, an exhaustive initial search is performed. The search algorithm tends to be conservative; if necessary, force fast peak finding, using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_FAST_FIND"})}),"."]}),"\n",(0,n.jsxs)(t.p,{children:["Using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_EXTRA_CANDIDATES"})}),", you can set the number of extra peaks to consider. Normally, the search algorithm considers only a limited number of (best) scores as possible candidates to a match when proceeding at the most subsampled stage. You can add robustness to the algorithm, by considering more candidates, without compromising too heavily on search speed. In addition, you can use ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_COARSE_SEARCH_ACCEPTANCE"})})," to set a minimum match score, valid at all levels except the last level, to be considered as an occurrence of the model. This ensures that possible models are not discarded at lower levels, yet maintains the required certainty during the final level."]}),"\n",(0,n.jsxs)(t.p,{children:["At the last (high-resolution) stage of the search, the model is large, so this stage can take a significant amount of time, even though the correlation function is evaluated at only a very few points. To save time, you can select a high search speed, using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_SPEED"})}),". For most models, this has little effect on the score or accuracy, but does increase speed."]}),"\n",(0,n.jsx)(t.h2,{id:"subpixel-accuracy",children:"Subpixel accuracy"}),"\n",(0,n.jsx)(t.p,{children:"The highest match score occurs at only one point, and drops off around this peak. The exact (subpixel) position of the model can be estimated from the match scores found on either side of the peak. A surface is fitted to the match scores around the peak and, from the equation of the surface, the exact peak position is calculated. The surface is also used to improve the estimate of the match score itself, which should be slightly higher at the true peak position than the actual measured value at the nearest whole pixel."}),"\n",(0,n.jsxs)(t.p,{children:["The actual accuracy that can be obtained depends on several factors, including the noise in the image and the particular pattern of the model. However, if these factors are ignored, the absolute limit on accuracy, imposed by the algorithm itself and by the number of bits and precision used to hold the correlation result, is about 0.025 pixels. This is the worst-case error measured in ",(0,n.jsx)(t.em,{children:"X"})," or ",(0,n.jsx)(t.em,{children:"Y"})," when an image is artificially shifted by fractions of a pixel. In a real application, accuracy better than 0.05 pixels is achieved for low-noise images. These numbers apply if you select high-accuracy search, using ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"MpatControl"})})," with ",(0,n.jsx)(t.a,{href:"/DOC_PUBLIC_AIL11_MD_HELP_SOURCE/Reference/pat/MpatControl",children:(0,n.jsx)(t.code,{children:"M_ACCURACY"})}),", in which case the search always proceeds to resolution level 0."]}),"\n",(0,n.jsx)(t.p,{children:"If you select medium accuracy (the default), the search might stop at resolution level 1, and hence the accuracy is half of what can be attained at level 0. Selecting low accuracy might cause the search to stop at level 2, so the accuracy is reduced by an additional factor of two (to about 0.2 pixel)."})]})}function d(e={}){const{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,n.jsx)(t,{...e,children:(0,n.jsx)(h,{...e})}):h(e)}},28453(e,t,a){a.d(t,{R:()=>s,x:()=>o});var r=a(96540);const n={},i=r.createContext(n);function s(e){const t=r.useContext(i);return r.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function o(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(n):e.components||n:s(e.components),r.createElement(i.Provider,{value:t},e.children)}}}]);